1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Empty / trivial cases ---
6	  it("empty quote → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums per item type (single-item quote, no modifiers, newcomer fresh customer adjustments excluded by using long-standing 2yr + follow-up — actually keep simple: use no modifiers via test inputs that neutralize all) ---
15	  // For isolation, the simplest approach: customer with 0 years, single item (first insurance applies). We will design test inputs so we can read off rules directly.
16	
17	  // Single item, no surcharges, fresh customer first contract: base + 10% first insurance + 5 fee
18	  it.todo("quote single sword (steel, ench 3), newcomer first contract → 100 + 10 + 5 = 115 G");
19	  it.todo("quote single amulet (silver, ench 2), newcomer first contract → 60 + 6 + 5 = 71 G");
20	  it.todo("quote single staff (wood, ench 1), newcomer first contract → 80 + 8 + 5 = 93 G");
21	  it.todo("quote single potion (glass, ench 0), newcomer first contract → 40 + 4 + 5 = 49 G");
22	
23	  // --- Components and blocks ---
24	  it.todo("quote 2 runes, newcomer first contract → base 50 G; +5 first insurance (10% of 50) + 5 fee = 60 G");
25	  it.todo("quote 3 runes (block applies), newcomer first contract → base 60 G; +6 first ins + 5 fee = 71 G");
26	  it.todo("quote 4 runes (no block — block requires exactly 3) → base 100 G; +10 first ins + 5 fee = 115 G");
27	  it.todo("quote 7 runes → base 175 G (60 block + 4×25); +18 first ins (rounded up from 17.5) + 5 fee = 198 G");
28	
29	  // --- 'Alike' components clarification ---
30	  it.todo("quote 2 runes + 1 moonstone → base 75 G (no block: different types)");
31	  it.todo("quote 3 runes + 3 moonstones → base 120 G (two separate blocks of 60 each)");
32	
33	  // --- Item-specific modifiers ---
34	  it.todo("quote cursed sword (steel, ench 3), newcomer first → 100 + 50 curse + 10 first ins + 5 fee = 165 G");
35	  it.todo("quote sword with enchantment exactly 5 → high-enchantment surcharge applies (100 + 30 + 10 first ins + 5 fee = 145 G)");
36	  it.todo("quote sword with enchantment 4 → no high-enchantment surcharge (100 + 10 first ins + 5 fee = 115 G)");
37	  it.todo("quote cursed sword with enchantment 5 → both surcharges (100 + 50 + 30 + 10 first ins + 5 fee = 195 G)");
38	
39	  // --- Policy-wide modifiers: loyalty threshold ---
40	  it.todo("customer with exactly 2 years → loyalty discount applies (sword steel ench 3: 100 + 10 first ins − 22 loyalty + 5 fee = 93 G)");
41	  it.todo("customer with 1 year → no loyalty discount (sword steel ench 3 → 115 G)");
42	
43	  // --- First-insurance surcharge always applies per item (clarifying ❓) ---
44	  it.todo("long-standing customer's brand-new sword still gets first-insurance surcharge per item");
45	
46	  // --- Follow-up contract discount ---
47	  it.todo("second quote in scenario → follow-up contract discount (15%) applies on policy total");
48	
49	  // --- Modifier scope: cursed surcharge applies only to cursed item, loyalty/follow-up apply to policy ---
50	  it.todo("cursed sword + plain amulet, newcomer first contract → policy base 160 + 50 curse + 16 first ins (10% of 160) + 5 fee = 231 G");
51	
52	  // --- Rounding in MHPCO's favor ---
53	  it.todo("premium calculation yielding 197.5 → rounded up to 198 G");
54	
55	  // --- Integration examples ---
56	  it.todo("newcomer (0y, no prev contract) with cursed sword (steel, ench 3) → premium 165 G");
57	  it.todo("3y customer's second quote of cursed sword (steel, ench 7) → premium 160 G");
58	
59	  // --- Unknown item type error ---
60	  it.todo("quote with unknown item type (broomstick) → throws (CLI must exit non-zero, stderr message)");
61	
62	  // --- Claims: basic standard reimbursement ---
63	  it.todo("standard reimbursement: regular sword (steel, ench 3) damage 500 → payout 400");
64	  it.todo("damage to a rune (insurance value 250), damage 200 → payout 100");
65	
66	  // --- Claims: enchantment >= 8 50% reimbursement ---
67	  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");
68	
69	  // --- Claims: dragon material full reimbursement ---
70	  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (full minus deductible)");
71	
72	  // --- Claims: dragon wins over high-enchantment ---
73	  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% wins, then deductible)");
74	  it.todo("dragon-material sword, enchantment exactly 8, damage 1000 → payout 400 (high-enchant clause applies, then deductible)");
75	
76	  // --- Claims: deductible per damage event ---
77	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible applies per damaged item)");
78	
79	  // --- Claims: multiple items of same type ---
80	  it.todo("policy with 2 swords, dragon damages both — each entry treated as separate damage with own deductible");
81	  it.todo("claim with more sword damages than swords insured → CLI exits non-zero, whole claim rejected");
82	
83	  // --- Claims: cap exhaustion ---
84	  it.todo("policy sword + amulet: insurance sum 1600, cap 3200");
85	  it.todo("cursed sword (modified premium) → cap based on unmodified insurance value: cap 2000");
86	  it.todo("policy sword + 3 runes (block): insurance sum 1750 (block discount affects premium only)");
87	  it.todo("sword insured (cap 2000); two successive claims of 1500 each → 1st payout 1400 remainingCap 600; 2nd payout 600 remainingCap 0");
88	
89	  // --- Claims: payout rounding (down, MHPCO favor) ---
90	  it.todo("payout calculation yielding 350.5 → rounded down to 350");
91	
92	  // --- Claims: error cases ---
93	  it.todo("claim references damage entry whose item is not part of policy → exits non-zero, stderr");
94	  it.todo("claim references damage with unknown item type → exits non-zero, stderr");
95	  it.todo("claim with damage amount -200 → exits non-zero, stderr");
96	});
